/// <summary>
///    The <c>ETGPurchRegisterReportUIBuilder</c> class is the user interface builder class for the associated SQL
///    Server Reporting Services (SSRS) report.
/// </summary>
class Etg_RegisterPurchReportUIBuilder extends SrsReportDataContractUIBuilder
{

       Etg_registerPurchContract  contract;

}

Method.Source:
/// <summary>
///    building all parameters
/// </summary>
public void build()
{
    contract = this.dataContractObject();

this.addDialogField(methodStr(Etg_registerPurchContract, parmFromDate), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmToDate), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmFinancialDimSet), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmIsDetailReport), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmViewConfigId), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmViewInventSizeId), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmViewInventColorId), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmViewInventStyleId), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmViewInventSiteId), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmViewInventLocationId), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmViewWMSLocationId), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmViewLicensePlateId), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmViewInventStatus), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmViewInventBatchId), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmViewInventSerialId), contract);
this.addDialogField(methodStr(Etg_registerPurchContract, parmViewInventOwnerId_RU), contract);
}

/// <summary>
///    creating dialog fields
/// </summary>
public void postBuild()
{
    DialogField     finDimSet;

    super();

    finDimSet = this.bindInfo().getDialogField(this.dataContractObject(), methodStr(Etg_registerPurchContract, parmFinancialDimSet));
    finDimSet.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(Etg_RegisterPurchReportUIBuilder, finDimSetLookup), this);
}

/// <summary>
///    creating dimension sets lookup
/// </summary>
/// <param name = "_formStringControl">form string control</param>
public void finDimSetLookup(FormStringControl   _formStringControl)
{
    Query                   query = new Query();
    QueryBuildDataSource    qbds;
    SysTableLookup          sysTableLookup = SysTableLookup::newParameters(tablenum(DimensionHierarchy), _formStringControl);

    sysTableLookup.addLookupfield(fieldNum(DimensionHierarchy, Name));
    sysTableLookup.addLookupfield(fieldNum(DimensionHierarchy, Description));

    qbds = query.addDataSource(tableNum(DimensionHierarchy));
    qbds.addRange(fieldNum(DimensionHierarchy, StructureType)).value(queryValue(DimensionHierarchyType::Focus));
    qbds.addRange(fieldNum(DimensionHierarchy, IsSystemGenerated)).value(queryValue(NoYes::No));

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}
